import javax.swing.*;
public class SwingUtilDemo {
    public static void main(String[] args) throws Exception {
        System.out.println(SwingUtilities.isEventDispatchThread());
        SwingUtilities.invokeAndWait(() ->
            System.out.println(SwingUtilities.isEventDispatchThread())
        );
        System.out.println(SwingUtilities.isEventDispatchThread());
    }
}
